#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char N[9];
        scanf("%s", N);
        int max = 0;
        for (int i = 0; i < strlen(N); i++) {
            char rotated[9];
            strcpy(rotated, N + i);
            strcat(rotated, N);
            rotated[strlen(N) + i] = '\0';
            int num = atoi(rotated + i);
            if (num > max) max = num;
        }
        printf("%d\n", max);
    }
    return 0;
}

