code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String N = sc.next();
            int max = 0;
            for (int i = 0; i < N.length(); i++) {
                String rotated = N.substring(i) + N.substring(0, i);
                int num = Integer.parseInt(rotated);
                if (num > max) max = num;
            }
            System.out.println(max);
        }
    }
}

